// Signal Assembler — merge 3 Groq outputs by article_url
function genUuid() {
  return 'xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx'.replace(/[xy]/g, function (c) {
    const r = Math.floor(Math.random() * 16);
    const v = c === 'x' ? r : (r & 0x3) | 0x8;
    return v.toString(16);
  });
}

function parseGroq(item) {
  if (!item || !item.json) return null;
  let content = null;
  const j = item.json;
  try {
    content = j.choices && j.choices[0] && j.choices[0].message
      ? j.choices[0].message.content : null;
  } catch (e) { content = null; }
  if (content == null) {
    // some HTTP nodes nest the body under .data / .body
    const body = j.data || j.body;
    if (body && body.choices) content = body.choices[0].message.content;
  }
  if (content == null) return null;
  let text = String(content).trim();
  text = text.replace(/^\`\`\`(?:json)?/i, "").replace(/\`\`\`$/, "").trim();
  const start = text.indexOf("[");
  const end = text.lastIndexOf("]");
  if (start !== -1 && end !== -1 && end > start) text = text.slice(start, end + 1);
  try { return JSON.parse(text); }
  catch (e) { console.log("Groq parse failure:", e.message); return null; }
}

const all = $input.all();
const c1 = parseGroq(all[0]) || [];   // Core Claim Extractor
const c2 = parseGroq(all[1]) || [];   // Information Age Scorer
const c3 = parseGroq(all[2]) || [];   // Company Mention Extractor

const byUrl = {};
const ensure = (url) => (byUrl[url] = byUrl[url] || { article_url: url });

for (const r of (Array.isArray(c1) ? c1 : [])) {
  if (!r || !r.article_url) continue;
  const o = ensure(r.article_url);
  o.core_claim = r.core_claim != null ? r.core_claim : null;
  o.claim_type = r.claim_type != null ? r.claim_type : null;
}
for (const r of (Array.isArray(c2) ? c2 : [])) {
  if (!r || !r.article_url) continue;
  const o = ensure(r.article_url);
  o.information_age_score = typeof r.information_age_score === "number" ? r.information_age_score : null;
  o.is_recycled = typeof r.is_recycled === "boolean" ? r.is_recycled : null;
  o.narrative_label = r.narrative_label != null ? r.narrative_label : null;
}
for (const r of (Array.isArray(c3) ? c3 : [])) {
  if (!r || !r.article_url) continue;
  ensure(r.article_url).companies_mentioned = r.companies_mentioned || [];
}

let sourceArticles = [];
try { sourceArticles = $('Aggregate for Groq').first().json.articles || []; } catch (e) {}
const metaByUrl = {};
for (const a of sourceArticles) metaByUrl[a.article_url] = a;

const runId = genUuid();
const now = new Date().toISOString();

const records = Object.values(byUrl).map(o => {
  const meta = metaByUrl[o.article_url] || {};
  return {
    article_url: o.article_url,
    headline: meta.headline || null,
    summary: meta.summary || null,
    source: meta.source || null,
    published_at: meta.published_at || null,
    core_claim: o.core_claim || null,
    claim_type: o.claim_type || null,
    information_age_score: o.information_age_score == null ? null : o.information_age_score,
    is_recycled: o.is_recycled == null ? null : o.is_recycled,
    narrative_label: o.narrative_label || null,
    companies_mentioned: o.companies_mentioned || [],
    first_appearance_date: now,
    appearance_count: 1,
    agent_run_id: runId,
    processed_at: now
  };
});

// One item per record so the Supabase upsert maps cleanly.
// Run-level metadata is recomputed by Generate Report from these records.
return records.map(r => ({ json: r }));

// Generate Report — build the markdown signal report
const records = $('Signal Assembler').all().map(i => i.json);
const runId = records.length ? records[0].agent_run_id : "n/a";
const runTimestamp = new Date().toISOString();

const total = records.length;
const novel = records.filter(r => (r.information_age_score || 0) >= 60);
const recycled = records.filter(r => r.is_recycled === true);
const novelCount = novel.length;
const recycledCount = recycled.length;

const fmt = v => (v == null || v === "" ? "—" : v);
const companiesOf = r => {
  const cm = r.companies_mentioned || [];
  return cm.length ? cm.map(c => c.ticker || c.companyName).join(", ") : "None";
};

// company coverage
const compStats = {};
for (const r of records) {
  for (const c of (r.companies_mentioned || [])) {
    const key = c.ticker || c.companyName;
    if (!key) continue;
    if (!compStats[key]) compStats[key] = { ticker: c.ticker || "—", name: c.companyName || key, count: 0, sum: 0 };
    compStats[key].count++;
    compStats[key].sum += (r.information_age_score || 0);
  }
}
const companyList = Object.values(compStats).sort((a, b) => b.count - a.count);

// narrative clusters
const clusters = {};
for (const r of records) {
  const label = r.narrative_label || "Unlabeled";
  if (!clusters[label]) clusters[label] = { count: 0, sum: 0, sources: new Set() };
  clusters[label].count++;
  clusters[label].sum += (r.information_age_score || 0);
  if (r.source) clusters[label].sources.add(r.source);
}
const clusterList = Object.entries(clusters)
  .map(([label, c]) => ({ label, count: c.count, avg: Math.round(c.sum / c.count), sources: [...c.sources] }))
  .sort((a, b) => b.count - a.count);
const topNarrative = clusterList.length ? clusterList[0].label : "—";

// classification buckets
const bucket = (lo, hi) => records.filter(r => (r.information_age_score || 0) >= lo && (r.information_age_score || 0) <= hi).length;
const b80 = bucket(80, 100), b50 = bucket(50, 79), b20 = bucket(20, 49), b0 = bucket(0, 19);

const L = [];
L.push("# Media Narrative Tracker — Signal Report");
L.push("**Run ID:** " + runId);
L.push("**Generated:** " + runTimestamp);
L.push("**Period:** Last 6 hours");
L.push("");
L.push("---");
L.push("");
L.push("## Executive Summary");
L.push("");
L.push("| Metric | Value |");
L.push("|--------|-------|");
L.push("| Articles processed | " + total + " |");
L.push("| Novel signals (score ≥ 60) | " + novelCount + " |");
L.push("| Recycled narratives | " + recycledCount + " |");
L.push("| Companies mentioned | " + (companyList.map(c => c.name).join(", ") || "None") + " |");
L.push("| Most active narrative | " + topNarrative + " |");
L.push("");
L.push("---");
L.push("");
L.push("## Novel Signals");
L.push("*Articles with information age score ≥ 60 — worth reading*");
L.push("");
if (!novel.length) {
  L.push("_No novel signals in this run._");
  L.push("");
} else {
  for (const r of novel.sort((a, b) => (b.information_age_score || 0) - (a.information_age_score || 0))) {
    L.push("### " + fmt(r.headline));
    L.push("**Source:** " + fmt(r.source) + " | **Score:** " + fmt(r.information_age_score) + "/100 | **Claim type:** " + fmt(r.claim_type) + " | **Companies:** " + companiesOf(r));
    L.push("**Core claim:** " + fmt(r.core_claim));
    L.push("**Narrative:** " + fmt(r.narrative_label));
    L.push("**Published:** " + fmt(r.published_at));
    L.push("**URL:** " + fmt(r.article_url));
    L.push("");
  }
}
L.push("---");
L.push("");
L.push("## Recycled Narratives");
L.push("*Articles with information age score < 40 — noise*");
L.push("");
const recList = records.filter(r => (r.information_age_score || 0) < 40);
if (!recList.length) {
  L.push("_No recycled narratives in this run._");
  L.push("");
} else {
  L.push("| Headline | Source | Score | Narrative Label |");
  L.push("|----------|--------|-------|-----------------|");
  for (const r of recList.sort((a, b) => (a.information_age_score || 0) - (b.information_age_score || 0))) {
    L.push("| " + fmt(r.headline) + " | " + fmt(r.source) + " | " + fmt(r.information_age_score) + " | " + fmt(r.narrative_label) + " |");
  }
  L.push("");
}
L.push("---");
L.push("");
L.push("## Narrative Clusters");
L.push("*Articles grouped by narrative label*");
L.push("");
if (!clusterList.length) {
  L.push("_No narratives to cluster._");
  L.push("");
} else {
  for (const c of clusterList) {
    L.push("**" + c.label + "** — " + c.count + " articles, avg score: " + c.avg);
    L.push("Sources: " + (c.sources.join(", ") || "—"));
    L.push("");
  }
}
L.push("---");
L.push("");
L.push("## Company Coverage");
L.push("*Which watchlist companies appeared in this run*");
L.push("");
L.push("| Company | Ticker | Mentions | Avg Age Score |");
L.push("|---------|--------|----------|---------------|");
if (!companyList.length) {
  L.push("| None | — | 0 | — |");
} else {
  for (const c of companyList) {
    L.push("| " + c.name + " | " + c.ticker + " | " + c.count + " | " + Math.round(c.sum / c.count) + " |");
  }
}
L.push("");
L.push("---");
L.push("");
L.push("## Signal Classification Summary");
L.push("");
L.push("| Score Range | Label | Count |");
L.push("|-------------|-------|-------|");
L.push("| 80–100 | Genuinely New | " + b80 + " |");
L.push("| 50–79 | Partially New | " + b50 + " |");
L.push("| 20–49 | Likely Recycled | " + b20 + " |");
L.push("| 0–19 | Recycled | " + b0 + " |");
L.push("");
L.push("---");
L.push("");
L.push("## Known Limitations");
L.push("- RSS coverage limited to 5 outlets (FT, Reuters, Seeking Alpha, CNBC, Yahoo Finance). Trade press narratives may not appear until picked up here.");
L.push("- Information age scores are Groq estimates, not validated against a labeled ground truth dataset.");
L.push("- Narrative label consistency across runs is unvalidated. Same narrative may receive slightly different labels.");
L.push("");
L.push("---");
L.push("");
L.push("*Mycroft — Media Narrative Tracker | Agent 3*");
L.push("*Stack: n8n + Groq (llama-3.3-70b-versatile) + Supabase*");

const report = L.join("\n");

return [{
  json: {
    report,
    runId,
    totalProcessed: total,
    novelCount,
    recycledCount
  }
}];
